const nightmareMeowtisNodes: Node[] = [
  { id: "nm-intro", type: "musicState", position: { x: 96, y: 390 }, data: { label: "Nightmare Lullaby", intensity: 20, looping: false, stems: ["music_box_broken_lullaby", "strings_nightmare_blanket", "synth_sleep_paralysis_purr"], asset: "mus_meowtsis_nightmare_lullaby_intro", directorNote: "The Nightmare of Mensis but it's a kitten having the worst nap of its life. The entire level takes place in a dreamscape made of oversized pillows, tangled blankets, and alarm clocks that go off at random. The music box should sound like it's been left in the rain and learned resentment.", status: "temp", jiraTicket: "BB-501" } },
  { id: "nm-explore", type: "musicState", position: { x: 544, y: 210 }, data: { label: "Frenzy Nap", intensity: 30, looping: true, stems: ["music_box_broken_lullaby", "cello_restless_dreaming", "harp_pillow_feather_fall", "perc_tossing_turning"], asset: "mus_meowtsis_frenzy_nap_loop", directorNote: "Frenzy in Bloodborne but it's caused by a kitten being too cozy. The Frenzy meter fills when the kitten finds an especially warm spot. At max Frenzy, the kitten falls asleep involuntarily for 3 seconds. In a boss fight. The music should oscillate between oppressively cozy and genuinely unsettling.", status: "temp" } },
  { id: "nm-explore-2", type: "musicState", position: { x: 544, y: 570 }, data: { label: "Bad Dream Wandering", intensity: 25, looping: true, stems: ["synth_sleep_paralysis_purr", "strings_nightmare_blanket", "pad_warm_milk_gone_cold"], asset: "mus_meowtsis_bad_dream_explore", status: "placeholder" } },
  { id: "nm-trans-to-combat", type: "transition", position: { x: 992, y: 180 }, data: { label: "\u2192 Pillow War", duration: 2000, syncPoint: "immediate", fadeType: "sting", status: "temp" } },
  { id: "nm-combat-lo", type: "musicState", position: { x: 1408, y: 120 }, data: { label: "Pillow Skirmish", intensity: 65, looping: true, stems: ["perc_pillow_slam", "brass_blanket_fort_charge", "strings_nightmare_unraveling", "synth_alarm_clock_fury"], asset: "mus_meowtsis_pillow_fort_combat_lo", status: "temp", jiraTicket: "BB-505" } },
  { id: "nm-combat-hi", type: "musicState", position: { x: 1408, y: 420 }, data: { label: "Micolan's Pillow Fort", intensity: 95, looping: true, stems: ["everything_micolan_pillow_fort_phase1"], asset: "mus_meowtsis_micolan_boss_loop", directorNote: "Micolan is a tuxedo cat who built a pillow fort so elaborate it has load-bearing cushions and a structural blanket framework. He runs through the fort screaming 'GRANT US TREATS! GRANT US TREATS!' The chase sequence music should be frantic but also kind of adorable. He occasionally stops running to bat at a dangling string, giving the player a window to attack.", status: "placeholder", jiraTicket: "BB-506" } },
  { id: "nm-param-naptime", type: "parameter", position: { x: 96, y: 645 }, data: { label: "NapTimeProximity", paramName: "RTPC_NapTimeProximity", minValue: 0, maxValue: 100, defaultValue: 50, description: "How close the kitten is to falling asleep. Increases near warm spots, soft surfaces, and sunbeams. At 100, involuntary nap triggers. The music gets progressively drowsier \u2014 tempo micro-decreases, reverb increases, and a gentle snoring stem fades in.", status: "placeholder" } },
  { id: "nm-param-purr", type: "parameter", position: { x: 96, y: 870 }, data: { label: "PurrIntensity", paramName: "RTPC_PurrIntensity", minValue: 0, maxValue: 100, defaultValue: 0, description: "Driven by comfort level during the nightmare. The purr is involuntary and betrays the kitten's position to enemies. At 100, the purr becomes a low rumble that shakes loose pillow feathers and can actually damage the environment. The music adds a subsonic purr drone that rattles speakers.", status: "temp" } },
  { id: "nm-trans-to-explore", type: "transition", position: { x: 992, y: 510 }, data: { label: "\u2192 Restless Nap", duration: 6000, syncPoint: "next-bar", fadeType: "bridge" } },
  { id: "nm-stinger-collapse", type: "stinger", position: { x: 544, y: 840 }, data: { label: "Pillow Fort Collapse", trigger: "OnPillowFortCollapse", asset: "mus_meowtsis_stinger_pillow_fort_collapse", priority: "critical", status: "placeholder" } },
  { id: "nm-stinger-blanket", type: "stinger", position: { x: 992, y: 840 }, data: { label: "Blanket Stolen", trigger: "OnBlanketStolen", asset: "mus_meowtsis_stinger_blanket_stolen", priority: "high", status: "temp" } },
  { id: "nm-ending", type: "musicState", position: { x: 1824, y: 390 }, data: { label: "Sweet Dreams", intensity: 35, looping: false, stems: ["music_box_broken_lullaby", "strings_nightmare_blanket", "harp_pillow_feather_fall"], asset: "mus_meowtsis_ending_sweet_dreams", status: "placeholder" } },
  { id: "nm-event-micolan-chase", type: "event", position: { x: 96, y: 120 }, data: { label: "Micolan's Pillow Fort Chase", eventType: "scripted_sequence", blueprintRef: "BP_ScriptedSeq_MicolanChase_01", description: "Scripted sequence: Micolan sprints through his pillow fort, knocking over cushion walls and scrambling over blanket ramparts. The player must chase him through an ever-collapsing labyrinth of bedding. He screams cat puns about the cosmos. 'A-MEOW-ZING! The cosmos, of course!' He is insufferable and beloved.", directorNote: "The chase music needs to loop seamlessly as Micolan runs through 4 distinct fort rooms. Each room transition should add a layer. By room 4, we should have full orchestra plus the alarm clock synth doing 16th notes. When he stops to bat at the string, the music drops to just the music box.", status: "temp", jiraTicket: "BB-512" } },
  { id: "nm-event-calico-reborn", type: "event", position: { x: 1824, y: 80 }, data: { label: "The One Reborn as a Calico", eventType: "cinematic", blueprintRef: "BP_CinematicTrigger_CalicoReborn", description: "Cinematic: a pile of discarded cat toys assembles itself into a massive calico-patterned abomination. Mouse toys for ears, feather wands for whiskers, jingle balls for eyes. It is The One Reborn \u2014 reassembled from every toy that was batted under the couch and forgotten. It wants revenge.", status: "placeholder" } },
];

