const huntersNapNodes: Node[] = [
  { id: "hn-intro", type: "musicState", position: { x: 96, y: 390 }, data: { label: "The Doll's Lullaby", intensity: 15, looping: false, stems: ["music_box_porcelain_tender", "strings_gentle_memory", "harp_garden_gate"], asset: "mus_huntersnap_dolls_lullaby_intro", directorNote: "The Hunter's Dream but it's a cozy cottage where an elderly porcelain cat doll tends a garden of tiny cat graves. Each grave has a different cat name and a small toy mouse headstone. The Doll's Lullaby music box should be the most heartbreakingly beautiful thing in the entire game. Players should need a moment.", status: "placeholder", jiraTicket: "BB-601" } },
  { id: "hn-explore", type: "musicState", position: { x: 544, y: 210 }, data: { label: "Garden of Cat Graves", intensity: 25, looping: true, stems: ["music_box_porcelain_tender", "cello_memorial_purr", "harp_tombstone_wind", "perc_pawprint_path"], asset: "mus_huntersnap_garden_of_cat_graves_loop", directorNote: "Each grave marker has an epitaph. 'Mr. Whiskers \u2014 Used All Nine.' 'Sergeant Fluffington \u2014 Died Doing What He Loved (Napping).' 'Princess Butterscotch \u2014 She Knocked The Vase Off The Table And The Table Off The Floor.' The music should honor each of these fallen heroes with quiet dignity.", status: "placeholder" } },
  { id: "hn-explore-2", type: "musicState", position: { x: 544, y: 570 }, data: { label: "Workshop Memories", intensity: 20, looping: true, stems: ["strings_gentle_memory", "piano_old_toys", "pad_fireside_warmth"], asset: "mus_huntersnap_workshop_explore", directorNote: "The workshop where the kitten upgrades its pajamas and weapons (which are all cat toys). The piano should sound like someone remembering how to play after a very long time. Warm but with an undercurrent of 'this dream cannot last.'", status: "placeholder" } },
  { id: "hn-trans-to-combat", type: "transition", position: { x: 992, y: 180 }, data: { label: "\u2192 Final Nap", duration: 4000, syncPoint: "next-bar", fadeType: "crossfade", status: "placeholder" } },
  { id: "hn-boss-p1", type: "musicState", position: { x: 1408, y: 120 }, data: { label: "Ghalman Phase 1", intensity: 70, looping: true, stems: ["perc_wheelchair_rhythm", "brass_old_hunter_fury", "strings_final_lullaby", "choir_nine_lives_spent"], asset: "mus_huntersnap_ghalman_phase1_loop", directorNote: "Ghalman is a very old, very large orange tabby in a tiny wheelchair. He stands up from the wheelchair and it is the most dramatic moment in gaming. He was sitting in it by choice. He is enormous. The wheelchair rhythm perc continues even after he stands \u2014 it's become part of the music, a memory of rest he's leaving behind.", status: "placeholder", jiraTicket: "BB-605" } },
  { id: "hn-boss-p2", type: "musicState", position: { x: 1408, y: 390 }, data: { label: "Ghalman Phase 2", intensity: 85, looping: true, stems: ["perc_wheelchair_rhythm", "brass_last_stand_full", "choir_eternal_naptime", "strings_final_lullaby", "organ_dream_requiem"], asset: "mus_huntersnap_ghalman_phase2_loop", directorNote: "Ghalman reveals his weapon \u2014 a prosthetic back-scratcher that transforms into a laser pointer. The choir sings 'Eternal Naptime' in cat Latin (Felinese). The organ should feel like a cathedral built from scratching posts. This is simultaneously the saddest and funniest boss fight in the game.", status: "placeholder", jiraTicket: "BB-606" } },
  { id: "hn-boss-p3", type: "musicState", position: { x: 1408, y: 630 }, data: { label: "Ghalman Phase 3", intensity: 100, looping: true, stems: ["everything_ghalman_phase3_transcendent"], asset: "mus_huntersnap_ghalman_phase3_loop", directorNote: "Ghalman removes his tiny reading glasses and places them gently on the wheelchair. He is ready. The tempo increase to 155 should feel like the dream itself is accelerating toward waking. Every motif from every previous level should appear here, transformed. The Central Yarnball's purr engine. The Litterbox's scoop rhythm. The Cat Tower's waltz. All woven together into one final, glorious, absurd tapestry of cat combat.", status: "placeholder" } },
  { id: "hn-secret-boss", type: "musicState", position: { x: 1824, y: 630 }, data: { label: "Moon Presence Belly Rub", intensity: 100, looping: true, stems: ["everything_moon_presence_belly_rub"], asset: "mus_huntersnap_moon_presence_boss", directorNote: "The secret boss. The Moon Presence descends and it is an incomprehensibly vast cosmic cat that rolls over to reveal its belly. This is a trap. Every cat owner knows this is a trap. The belly rub is the final test. The music should convey lovecraftian horror mixed with the irresistible urge to pet the tummy. 160 BPM of pure cosmic cat chaos.", status: "placeholder", jiraTicket: "BB-608" } },
  { id: "hn-param-catnip", type: "parameter", position: { x: 96, y: 660 }, data: { label: "CatnipLevel", paramName: "RTPC_CatnipLevel", minValue: 0, maxValue: 100, defaultValue: 0, description: "The final parameter. Catnip level determines which ending the player gets. Below 30: Accept the Nap (wake up, forget the dream). 30-70: Refuse the Nap (become the new dream guardian). Above 70: Consume the Catnip (ascend to become an infant Great One \u2014 a tiny cosmic kitten). The music responds to all three thresholds with different harmonic palettes.", status: "placeholder" } },
  { id: "hn-trans-to-explore", type: "transition", position: { x: 992, y: 510 }, data: { label: "\u2192 Dream Garden", duration: 6000, syncPoint: "next-bar", fadeType: "bridge" } },
  { id: "hn-stinger-wheelchair", type: "stinger", position: { x: 544, y: 840 }, data: { label: "Wheelchair Creak", trigger: "OnWheelchairCreak", asset: "mus_huntersnap_stinger_wheelchair_creak", priority: "medium", status: "placeholder" } },
  { id: "hn-stinger-bell", type: "stinger", position: { x: 992, y: 840 }, data: { label: "Final Bell Ring", trigger: "OnFinalBellRing", asset: "mus_huntersnap_stinger_final_bell", priority: "critical", status: "placeholder" } },
  { id: "hn-stinger-secret", type: "stinger", position: { x: 1408, y: 870 }, data: { label: "Secret Boss Trigger", trigger: "OnSecretBossTrigger", asset: "mus_huntersnap_stinger_secret_boss", priority: "critical", status: "placeholder" } },
  { id: "hn-ending", type: "musicState", position: { x: 1824, y: 390 }, data: { label: "Accept the Nap", intensity: 30, looping: false, stems: ["music_box_porcelain_tender", "strings_gentle_memory", "choir_goodnight_hunter", "harp_final_dream"], asset: "mus_huntersnap_ending_accept_the_nap", directorNote: "The kitten curls up. The music box plays one last time. Every stem from every level appears for one bar each, then fades. The final sound is a single purr that decays into silence. Then the credits roll over the sleeping kitten. The player should be emotionally destroyed in the gentlest possible way.", status: "placeholder" } },
  { id: "hn-event-ghalman-offer", type: "event", position: { x: 96, y: 120 }, data: { label: "Ghalman's Final Offer", eventType: "cinematic", blueprintRef: "BP_CinematicTrigger_GhalmanOffer", description: "Cinematic: Ghalman wheels up to the kitten in his tiny wheelchair. 'Tonight, Ghalman joins the nap,' he says, which doesn't make grammatical sense but the voice acting sells it. He offers the kitten a choice: accept the nap and wake up, or refuse and stay in the dream forever. His whiskers tremble. He has been napping for centuries.", directorNote: "The music must stop completely when Ghalman speaks. Just ambient garden sounds. When he finishes his offer, hold 4 beats of silence before the player choice UI appears. The weight of this moment should be unbearable. It's a cat in a wheelchair offering another cat a nap.", status: "placeholder", jiraTicket: "BB-612" } },
  { id: "hn-event-moon-qte", type: "event", position: { x: 1824, y: 120 }, data: { label: "Moon Presence Descends", eventType: "qte", blueprintRef: "BP_QTE_MoonPresenceBellyRub", description: "QTE: The cosmic cat rolls over. The player must resist the urge to touch the belly through a series of increasingly difficult button prompts. Each failed prompt results in the kitten involuntarily reaching for the tummy. Success means the kitten achieves cosmic transcendence. Failure means getting grabbed by all four paws and bunny-kicked into oblivion.", status: "placeholder" } },
  { id: "hn-event-checkpoint-dream", type: "event", position: { x: 96, y: 840 }, data: { label: "Ending: Accept the Nap", eventType: "checkpoint", blueprintRef: "BP_Checkpoint_DreamGarden_Final", description: "Final checkpoint. The kitten has one last chance to change its mind before the dream ends. The checkpoint lantern here is the original fish nightlight from Central Yarnball, but older and dimmer. It still works. It has always worked.", status: "placeholder" } },
];

